mapper.select:
 SELECT
		DATE_FORMAT(REG_DATE, '%Y-%m') AS USER_MONTH, Count(*) AS USER_COUNT
		FROM MEMBER WHERE 1=1 
			AND ROLE = #{role}
		 GROUP BY USER_MONTH ORDER BY
		USER_MONTH;

